VALUES
  ('social-worker-moex-02661', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '針對政府近些年來推動脫貧方案，就社會工作者而言，下列有關實務操作的敘述何者錯誤？', '["有工作能力但未就業之低收入戶、新貧、近貧人口以及前述人員子女是脫貧行動三個優先適用對象", "透過共同參與，預防新貧、近貧人口進入低收入戶行列，促使已進入低收入戶行列人員及早脫離低收 入戶身分是脫貧行動的短期目標", "提升個體的能力，增進個體全面發展是脫貧行動的最終目的", "具體操作可經由清查工作、生產性服務、支持性服務彼此配套，以及妥適的資源管理達成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02662', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會團體工作中，自助團體被視為是經由了解幫助相同經驗者建構另一因應變通方案，協助成員滿足 其特殊需求，對此學者Riessman提到自主團體明顯的特徵，下列何者錯誤？', '["非競爭、合作導向", "菁英導向並有科層化型態", "強調本土化、內在的", "經由幫助別人獲得接受他人幫助的態度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02663', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近些年來，國內對於社會企業的推動極為積極和熱絡，對於社會工作者而言，社會企業也被視為解決並 處理弱勢者的經濟、就業及相關問題的一種新的組織型態，下列有關社會企業的定義何者錯誤？', '["社會企業是指一個致力於公共財，並以獲取利潤追求永續經營的組織", "經費來源除了有非營利組織的傳統經費來源，尚包括商業的營利收入以及商業的活動", "社會企業強調社會創新精神，兼容社會、經濟與政策三大目的，以解決身心障礙者與弱勢族群的失業 問題", "社會企業強調社會與經濟目標的融合，除偏重商業收益，補貼非營利組織的財政缺口也是一種新型態 的社會投資"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02664', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在擔任災難管理時的志工督導或管理者時，其對於志工的動員與管理的工作，下列敘述何者 錯誤？', '["督導或管理者必須讓志工以有組織的方式進入災區", "督導或管理者必須引導志工與倖存者有相當程度的隔絕與脫離", "督導或管理者必須引導志工及其他工作者有適切的結合與互補", "督導或管理者必須隨時注意志工的工作狀況與情緒反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02665', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '進步年代（Progressive Era）與睦鄰運動的價值觀念比較偏重於關注下列那一方面的問題？', '["行為問題", "認知問題", "社會結構問題", "文化問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02666', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者應與身障者建立「充權」的專業關係，下列何者不適用於「充權」敘述？', '["案主自決的倫理原則是促進社會融合的先決條件，應該視身障者為專家", "應依據過去的服務紀錄來判斷身障者的需求，而非只是聽從身障者自己的想法", "擴大身障者在日常生活中的選擇機會，提供積極復健計畫以增加自主與獨立", "體會身障者被邊緣化與烙印的感受，協助其面對與家人和社區的社會互動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02667', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作理論中，有關問題解決學派的描述，下列何者錯誤？', '["特別關注於案主的理性能力和認知力量", "社會工作者和案主應該結成夥伴關係", "詳細地辨別、描述和量化問題", "特別適合用於反歧視的實務中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02668', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '睦鄰運動（Settlement House Movement）與慈善組織會社（Charity Organization Society）雖同為社會工作 的起源，但兩者的價值精神與意識形態是很不相同的。下列對兩者的敘述，何者錯誤？', '["兩者都深受宗教慈善救濟窮人的措施所影響，並以宣揚教義為最終目標", "兩者都致力於研究分析、試圖以科學的方法來解決傳統慈善無法處理的問題", "睦鄰運動將貧窮問題的理解從宗教與非經濟歸因，轉化到社會環境歸因", "慈善組織會社整合、協調資源的目的是避免資源重複浪費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02669', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的價值、知識與技術可分為「重視人」、「重視社會」、「重視專業行為」三方面。下列何者 不是社會工作專業所強調的價值與技術？', '["尊重多元性", "自我了解", "災變預測", "有效溝通"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02670', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '實踐「個人和政治權力的啟動，獲致感覺個人有能力和肯定自己的經驗，並進而能獲取機會、連結資源、 採取行動以對抗社會控制」等主張，最接近下列那一個社會工作理論觀點？', '["生態系統理論", "充權與倡導觀點", "心理及社會學派", "多元文化觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02671', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關女性主義社會工作的敘述，下列何者錯誤？', '["同樣身為女性，社會工作者要扮演「社會女工匠」的角色，致力於改造個案，脫離被父權壓迫的命運", "社會工作者應與個案秉持一種平等的關係，讓個案可以釋放自己、自我肯定與學習新的知識與能力", "拒絕性別盲目的知識和技術，改採取承認女性經驗的方法，來修正實務工作模式", "尋求集體主義式的解決方案，但尊重每一位女性的個體性和獨特性，例如原住民婦女、身心障礙婦女、 新移民等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02672', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一個社會工作實務原則不屬於社會心理學派的創見？', '["個別化原則", "人在情境中", "重視專業關係", "案主自我揭露"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02673', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在開個案研討會中，社會工作者稍微隱匿修改一下，然後將案主的資訊和與會者分享，事後也回收相關 資料；如此做法符合那一項專業倫理原則？', '["案主自決", "絕對保密", "相對保密", "最小傷害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02674', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會福利組織受到購買式服務契約與私有化的影響，在組織倫理方面比較著重於那一方面？', '["社會工作者的個人成長", "組織績效", "志工福利", "社會工作者的專業成長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02675', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作不當執業與倫理原則的敘述，何者錯誤？', '["當社會工作者發現自己沒有能力處理個案的問題時，應立即向更有經驗的同事或督導尋求諮詢或轉介 個案進行其他服務", "提供督導的社會工作者應以公平的態度來評估受督導者的表現，而非考量人際關係與情分深淺", "為了幫助個案取得較好的福利資源，社會工作者在報告上故意誇大一下個案的可憐處境，是維護案主 利益優先的倫理", "發現主管在下班後與個案發生性關係，基於維護機構利益、對組織表示忠誠，應該想辦法揭露、告發 其行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02676', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有人主張臺灣的公民沒有義務提供非法移工任何服務與協助，且機構的工作人員應該舉發逃逸外勞使其 被遣返回國是合乎倫理的；這樣的主張是屬於何種倫理觀點？', '["利他主義", "行為的效用主義", "馬克斯主義", "相對論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02677', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「在我15歲到18歲時，一直有位社會工作者在幫助我，當我離開機構後，開始思考上大學這件事，他 就帶我到每一所我想去的大學參訪，指導我如何租屋、申請學校、填寫經濟補助申請、給我很多做人做 事的建議，也協助我順利找到打工工作，賺取生活費」，請問這位社會工作者在做的是什麼方案？', '["獨立生活服務", "青年住宅輔導員", "學生助學貸款審核", "收養前的中途之家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02678', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近年來校園的暴力、霸凌事件頻傳，學校社會工作在臺灣，似乎可以有更積極的介入角色。下列何者不 屬於學校社會工作的範圍？', '["協助處理校園性侵害與性騷擾事件", "預防並輔導青少年未婚懷孕個案", "協助新移民家庭子女生活適應", "催化學校女性教職員爭取性別平等工作運動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02679', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '精神病理社會工作的介入理論包括心理學、器質性理論、社會文化理論等觀點。請問下列敘述何者正確？', '["重視器質性因素的學派主要關注的是荷爾蒙、生化平衡、神經傳導素、基因等，介入上是以抗精神疾 病藥物為主的醫療處遇", "心理學觀點認為心理疾病本身並不存在，主要是社會文化對人產生壓迫與迷思，造成個體的潛意識衝突", "行為主義、認知學派關注於檢視人的訊息處理過程對行為的影響，建議改變社會歧視，屬於社會文化 觀點", "人文主義觀點強調以人為中心，發展個人能力與潛力，干預重點是降低幻想與妄想，使獲致動機與優勢"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02680', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會救助與社會保險的比較，下列那一項錯誤？', '["社會救助的對象主要是低收入者，社會保險主要的對象是有工作的人", "通常社會救助是以需求為基礎來進行資格認定，社會保險則是以有無繳納保費來認定受益資格", "雙軌式福利論認為社會救助帶有標籤與歧視，且受助者通常是女性，因為女人比較容易落入貧窮", "工作福利（workfare）是社會保險的主流概念，目的是為了鼓勵、支持就業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02681', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「睦鄰運動」強調從社會環境的角度來解決社會問題，並以「Three R」來解決貧窮的問題。所謂「Three R」 指的是：', '["Research、Residence、Reform", "Research、Rehabilitation、Reform", "Residence、Responsibility、Reform", "Reaction、Research、Rehabilitation"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02682', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關認知行為治療法（CBT）之敘述，下列何者錯誤？', '["起源可追溯到實驗研究與學習理論", "分為古典制約法、操作制約法、社會學習論三大流派", "干預過程強調以診斷取代評估，療程著重在了解「為什麼」", "不只要改變顯性行為，還要改變隱性行為，以達到認知自助發展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02683', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關生態系統理論的敘述，何者錯誤？', '["生態系統關注的是人類和其棲息環境間的互動過程與其他物種的適應歷程", "個人的行動是目標取向的，為了適者生存，應該不斷強化個人的求生意志與競爭動機，以適應環境變遷", "生態理論可上溯至達爾文發表之進化論，尤其是適者生存法則", "應善用個人的生活經驗與非正式支持，作為干預的切入點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02684', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '馬克思主義（Marxism）被視為較為宏觀和批判的觀點與理論，其對於社會工作實務的影響，下列敘述何 者錯誤？', '["馬克思主義強調社會工作的功能是控制而非關懷", "馬克思主義認為社會工作與案主的關係存在著階級關係", "馬克思主義主張貧窮的問題是來自結構性的原因", "馬克思主義認為福利國家合法化制度性的不均，因此應廢除福利國家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02685', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不屬於批判取向／基變社會工作（radical social work）的技術？', '["集體化（collectivization）", "同化（assimilation）", "覺醒（consciousness raising）", "重新定義（redefining）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
